// ──── INSERTION ───────────────────────────────────────────────────────────────
async function insertFaqs() {
  console.log(`Insertion de ${faqs.length} FAQ (orders 51-80) dans app_faq...`);
  const batch = db.batch();
  faqs.forEach((faq) => {
    const ref = db.collection("app_faq").doc();
    batch.set(ref, faq);
  });
  await batch.commit();
  console.log(`✅ ${faqs.length} FAQ insérées avec succès (orders 51-80)`);
  process.exit(0);
}

insertFaqs().catch((err) => {
  console.error("❌ Erreur :", err.message);
  process.exit(1);
});
